```javascript
// Sample JSON data
const imageData = {
    "image": {
        "url": "https://example.com/butterfly.jpg",
        "width": 600,
        "height": 400,
        "alt": "A beautiful butterfly"
    }
};

// Function to load image data onto the page
function loadImage(data) {
    const container = document.getElementById('image-container');
    const img = document.createElement('img');

    img.src = data.image.url;
    img.width = data.image.width;
    img.height = data.image.height;
    img.alt = data.image.alt;

    container.appendChild(img);
}

// Load the image when the page loads
window.onload = function() {
    loadImage(imageData);
};
```

### Step 4: Verify the Image Display
Ensure that the image is displayed correctly on your website by opening the HTML file in a web browser. The image should appear with the correct dimensions and alt text.

